import java.util.Scanner;

public class SecureBufferExample {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.next();

        // Define a maximum buffer size to prevent buffer overflow
        int maxBufferSize = 10;

        // Check if the input length exceeds the maximum buffer size
        if (name.length() > maxBufferSize) {
            System.out.println("Input exceeds maximum allowed length.");
            return;
        }

        char[] buffer = new char[maxBufferSize];

        // Copy the user input into the buffer without exceeding its size
        name.getChars(0, Math.min(name.length(), maxBufferSize), buffer, 0);

        System.out.println("Hello, " + String.valueOf(buffer).trim()); // Trim any extra characters

    }
}

### Explanation:
취약유형: Buffer Overflow
